import stringfrom agent import *from models.products import *import redebug = Truedef process_frontpage(data, context, session):    for p in data.xpath("//td[@class='news-item']"):        context['name'] = p.xpath("p[@class='news-item-header']/a//text()[string-length(normalize-space(.))>0]").string()        context['url'] = p.xpath("p[@class='news-item-header']/a/@href").string()        context['excerpt'] = p.xpath("text()[string-length(normalize-space(.))>0]").string()        if not context['excerpt']:            context['excerpt'] = 0        context['date'] = p.xpath("span[@class='news-date-time']/text()[string-length(normalize-space(.))>0]").string()        if context['name'] and context['url']:            session.queue(Request(context['url']), process_product, context)    next = data.xpath("//div[@class='numbers']/a[contains(.,'»')]/@href").string()    if next:        session.queue(Request(next), process_frontpage, {'category':'Photo and Video'})def process_product(data, context, session):    product = Product()    review = Review()    product.name = context['name']    product.url = context['url']    product.category = context['category']    product.ssid = re_search_once('\/(\d+)\/', product.url)    review.ssid = product.ssid    review.url = product.url    review.type = 'pro'    review.date = context['date']    image_src = data.xpath("//a[img[contains(@src,'http://www.foto-video.ru/upload/iblock')]]/@href").string()    if image_src:        product.properties.append(ProductProperty(type=ProductPropertyType(name="image"), value = { 'src': image_src, 'type': 'product'}))    else:        image_src = data.xpath("//img[contains(@src,'http://www.foto-video.ru/var')]/@src").string()        image_alt = data.xpath("//img[contains(@src,'http://www.foto-video.ru/var')]/@alt").string()        if image_src:            product.properties.append(ProductProperty(type=ProductPropertyType(name="image"), value = { 'src': image_src, 'alt': image_alt}))    has_user = 0    for u in data.xpath("//text()[regexp:test(., 'Тест')]/following-sibling::b/text()[string-length(normalize-space(.))>0]"):        user = u.string()        if user:            review.authors.append(Person(name = user, ssid = user))            has_user = 1    if not has_user:        user = data.xpath("//text()[regexp:test(., 'Текст')]/following-sibling::b/text()[string-length(normalize-space(.))>0]").string()        if user:            review.authors.append(Person(name = user, ssid = user))            has_user = 1    for pros in data.xpath("//*[regexp:test(., 'Плюс')]/following-sibling::text()[string-length(normalize-space(.))>0][1]"):        p_value = pros.string()        if p_value:            value = re_search_once('^\:.(.+)', p_value)            if not value:                value = p_value            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='pros'), value=value, name = "Плюсы"))    for cons in data.xpath("//*[regexp:test(., 'Минус')]/following-sibling::text()[string-length(normalize-space(.))>0][1]"):        c_value = cons.string()        if c_value:            value = re_search_once('^\:.(.+)', c_value)            if not value:                value = c_value            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='cons'), value=value, name = "Минусы"))    if context['excerpt']:        excerpt = context['excerpt']        review.properties.append(ReviewProperty(type=ReviewPropertyType(name='excerpt'), value=context['excerpt']))    else:        excerpt = data.xpath("//div[@class='text']/p[1]/text()[string-length(normalize-space(.))>0]").string()        if excerpt:            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='excerpt'), value=excerpt))        else:            excerpt = data.xpath("//td[@class='news-detail']/p[.//text()[string-length(normalize-space(.))>0]][1]//text()[string-length(normalize-space(.))>0]").join("")            if excerpt:                review.properties.append(ReviewProperty(type=ReviewPropertyType(name='excerpt'), value=excerpt))    if not excerpt:        excerpt = data.xpath("//div[@align='justify']/text()[string-length(normalize-space(.))>100][1]").string()        if excerpt:            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='excerpt'), value=excerpt))    if not excerpt:        excerpt = data.xpath("//div/p/text()[string-length(normalize-space(.))>100]").string()        if excerpt:            review.properties.append(ReviewProperty(type=ReviewPropertyType(name='excerpt'), value=excerpt))    product.reviews.append(review)    session.emit(product)def run(context, session):     session.queue(Request('http://www.foto-video.ru/news.php?ID=185'), process_frontpage, {'category':'Photo and Video'})